import { BrowserRouter, Route, Routes, Navigate} from 'react-router-dom';
import './App.css'


function App() {
  return (
    <BrowserRouter>
      <div className="App">
        <Routes>
          <Route path="/login" element={<Login />}  />
          <Route path="/register" element={<Register />}/>
          <Route path="/layout/*" element={<Layout />} />
          <Route path="/" element={<Navigate to="/login"/>}/>
        </Routes>
      </div>
    </BrowserRouter>
  );
}

export default App;
